quickStart.basic:
import { ToolStream } from '@pedrofariasx/toolstream';

const parser = new ToolStream({ provider: 'openai' });

parser.on('tool-call:complete', (toolCall) => {
  console.log('Tool:', toolCall.name, toolCall.arguments);
});

for await (const chunk of stream) {
  parser.push(chunk);
}

parser.finalize();

quickStart.eventDriven:
import { ToolStream } from '@pedrofariasx/toolstream';

const parser = new ToolStream({ autoDetectProvider: true });

parser.on('tool-call:start', (call) => console.log('Detected:', call));
parser.on('tool-call:arguments:delta', (delta, partial, index) => {
  console.log('Arguments delta:', delta);
  console.log('Partial object:', partial);
});
parser.on('tool-call:complete', (call) => {
  console.log('Complete tool call:', call);
});

parser.push(chunk);
parser.finalize();

quickStart.earlyExecution:
import { ToolStream } from '@pedrofariasx/toolstream';

const parser = new ToolStream({
  provider: 'openai',
  earlyExecutionThreshold: 0.85,
});

parser.on('tool-call:early-execute', (toolCall) => {
  // Execute tool with partial arguments before stream ends
  executeTool(toolCall.name, toolCall.partialArguments);
});

quickStart.customAdapter:
import { ToolStream, BaseAdapter } from '@pedrofariasx/toolstream';
import type { NormalizedDelta, ProviderName } from '@pedrofariasx/toolstream';

class MyAdapter extends BaseAdapter {
  readonly name: ProviderName = 'custom';

  *processChunk(chunk: string): Generator<NormalizedDelta> {
    // Convert custom format to NormalizedDelta events
  }

  detect(chunk: string): boolean {
    return chunk.includes('my-format');
  }
}

const parser = new ToolStream({ customAdapter: new MyAdapter() });

quickStart.adapterUsage:
import { ToolStream } from '@pedrofariasx/toolstream';
import { AnthropicAdapter } from '@pedrofariasx/toolstream/adapters';

// Use a specific adapter directly
const parser = new ToolStream({ provider: 'anthropic' });

// Or access the registry
import { adapterRegistry } from '@pedrofariasx/toolstream';
const adapter = adapterRegistry.get('gemini');
parser.setCustomAdapter(adapter);
